# 웹 워커와 멀티스레딩 기반 성능 최적화

오늘은 웹 워커를 활용한 JavaScript 멀티스레딩과 고성능 웹 애플리케이션 구현 방법에 대해 집중적으로 공부했다. 특히 애니메이션이 많은 웹앱에서 성능 병목 현상을 해결하는 방법을 실험해봤다.

## 🔁 웹 워커 기본과 활용

무거운 작업을 메인 스레드에서 분리하기 위한 웹 워커에 대해 학습했다:

### 웹 워커 기본 구현

```javascript
// main.js (메인 스레드)
const worker = new Worker('worker.js');

document.getElementById('calculate-btn').addEventListener('click', () => {
  const num = parseInt(document.getElementById('number-input').value);
  
  // 워커에게 메시지 전송
  worker.postMessage({ type: 'CALCULATE_PRIMES', payload: num });
  
  // UI 업데이트 (진행 중 표시)
  document.getElementById('status').textContent = '계산 중...';
});

// 워커로부터 응답 수신
worker.onmessage = function(event) {
  const { type, payload } = event.data;
  
  if (type === 'PROGRESS') {
    document.getElementById('progress-bar').style.width = `${payload}%`;
  }
  else if (type === 'RESULT') {
    document.getElementById('status').textContent = '완료!';
    displayResults(payload);
  }
};

// worker.js (워커 스레드)
onmessage = function(event) {
  const { type, payload } = event.data;
  
  if (type === 'CALCULATE_PRIMES') {
    const primes = [];
    const num = payload;
    
    for (let i = 2; i <= num; i++) {
      // 진행률 보고 (10000개마다)
      if (i % 10000 === 0) {
        postMessage({
          type: 'PROGRESS',
          payload: Math.floor((i / num) * 100)
        });
      }
      
      let isPrime = true;
      for (let j = 2; j < i; j++) {
        if (i % j === 0) {
          isPrime = false;
          break;
        }
      }
      if (isPrime) primes.push(i);
    }
    
    // 결과 반환
    postMessage({
      type: 'RESULT',
      payload: primes
    });
  }
};
```

### 웹 워커 장단점 분석

👍 **장점**:
- 메인 스레드 블로킹 방지로 UI 반응성 유지
- 멀티코어 CPU 활용 가능
- 복잡한 계산, 데이터 처리에 적합

👎 **단점**:
- DOM 직접 접근 불가능 (메인 스레드와 통신 필요)
- 메모리 오버헤드 증가
- 스레드 간 통신에 시간 소요

## 🔄 SharedArrayBuffer와 Atomics

최근 웹 표준에 추가된 SharedArrayBuffer와 Atomics API에 대해서도 학습했다:

```javascript
// 메인 스레드
const buffer = new SharedArrayBuffer(4); // 4바이트 버퍼
const view = new Int32Array(buffer); // Int32 뷰

view[0] = 123; // 초기값 설정

const worker = new Worker('shared-worker.js');
worker.postMessage({ buffer }); // 워커에 공유 버퍼 전달

// 워커 스레드 (shared-worker.js)
onmessage = function(event) {
  const { buffer } = event.data;
  const view = new Int32Array(buffer);
  
  // Atomics.add로 원자적 연산 수행
  const oldValue = Atomics.add(view, 0, 42);
  console.log('이전 값:', oldValue); // 123
  console.log('새 값:', view[0]); // 165 (123 + 42)
  
  // 메인 스레드에 알림
  postMessage('완료');
};

// 메인 스레드에서 워커 응답 처리
worker.onmessage = function() {
  console.log('최종 값:', view[0]); // 165
};
```

## 🎨 캔버스 애니메이션 최적화

웹 워커와 이벤트 루프 지식을 활용해 캔버스 애니메이션을 최적화하는 프로젝트를 진행했다:

```javascript
// main.js
const canvas = document.getElementById('game-canvas');
const ctx = canvas.getContext('2d');
const particleWorker = new Worker('particle-worker.js');

// 게임 상태
let particles = []; // 파티클 데이터 저장
let rendering = false;

// 워커 초기화
particleWorker.postMessage({
  type: 'INIT',
  payload: {
    width: canvas.width,
    height: canvas.height,
    particleCount: 5000
  }
});

// 워커로부터 업데이트된 파티클 데이터 수신
particleWorker.onmessage = function(event) {
  const { type, payload } = event.data;
  
  if (type === 'UPDATE') {
    particles = payload;
    
    // 렌더링 중이 아니면 렌더링 시작
    if (!rendering) {
      rendering = true;
      requestAnimationFrame(render);
    }
  }
};

// 렌더링 함수 (메인 스레드에서 실행)
function render() {
  // 캔버스 지우기
  ctx.clearRect(0, 0, canvas.width, canvas.height);
  
  // 모든 파티클 그리기
  ctx.fillStyle = 'rgba(0, 150, 255, 0.5)';
  particles.forEach(particle => {
    ctx.beginPath();
    ctx.arc(particle.x, particle.y, particle.radius, 0, Math.PI * 2);
    ctx.fill();
  });
  
  // 다음 프레임 요청
  rendering = true;
  requestAnimationFrame(render);
}

// 애니메이션 시작
document.getElementById('start-btn').addEventListener('click', () => {
  particleWorker.postMessage({ type: 'START' });
});

// 애니메이션 정지
document.getElementById('stop-btn').addEventListener('click', () => {
  particleWorker.postMessage({ type: 'STOP' });
});

// particle-worker.js
let particles = [];
let width = 0;
let height = 0;
let animating = false;

// 메시지 핸들러
onmessage = function(event) {
  const { type, payload } = event.data;
  
  switch (type) {
    case 'INIT':
      width = payload.width;
      height = payload.height;
      initParticles(payload.particleCount);
      break;
      
    case 'START':
      animating = true;
      requestAnimationFrame(updateParticles);
      break;
      
    case 'STOP':
      animating = false;
      break;
  }
};

// 파티클 초기화
function initParticles(count) {
  particles = [];
  
  for (let i = 0; i < count; i++) {
    particles.push({
      x: Math.random() * width,
      y: Math.random() * height,
      vx: Math.random() * 2 - 1, // -1 ~ 1
      vy: Math.random() * 2 - 1, // -1 ~ 1
      radius: Math.random() * 3 + 1
    });
  }
  
  // 초기 데이터 메인 스레드로 전송
  postMessage({
    type: 'UPDATE',
    payload: particles
  });
}

// 파티클 업데이트 (애니메이션 프레임)
function updateParticles() {
  if (!animating) return;
  
  // 모든 파티클 위치 업데이트
  particles.forEach(particle => {
    // 위치 업데이트
    particle.x += particle.vx;
    particle.y += particle.vy;
    
    // 벽에 부딪힐 경우 반사
    if (particle.x < 0 || particle.x > width) {
      particle.vx *= -1;
    }
    
    if (particle.y < 0 || particle.y > height) {
      particle.vy *= -1;
    }
  });
  
  // 업데이트된 데이터 메인 스레드로 전송
  postMessage({
    type: 'UPDATE',
    payload: particles
  });
  
  // 다음 프레임 업데이트 예약
  setTimeout(() => {
    requestAnimationFrame(updateParticles);
  }, 16); // 약 60fps
}
```

## ⚠️ 발견한 성능 함정

프로젝트를 진행하면서 몇 가지 성능 함정을 발견했다:

1. **메시지 전달 오버헤드**:
   웹 워커와 통신 시 데이터 직렬화/역직렬화 비용이 큼 → SharedArrayBuffer 사용으로 개선

   ```javascript
   // 개선된 버전 - 공유 메모리 사용
   // main.js
   const buffer = new SharedArrayBuffer(Float32Array.BYTES_PER_ELEMENT * particleCount * 4);
   const particleData = new Float32Array(buffer);
   
   // particle-worker.js
   function updateParticles() {
     // 직접 공유 메모리에 쓰기
     for (let i = 0; i < particleCount; i++) {
       const baseIndex = i * 4;
       particleData[baseIndex] += particleData[baseIndex + 2]; // x += vx
       particleData[baseIndex + 1] += particleData[baseIndex + 3]; // y += vy
       
       // 경계 검사...
     }
     
     // 업데이트 완료 신호만 전송 (데이터 없음)
     postMessage({ type: 'FRAME_READY' });
   }
   ```

2. **불필요한 렌더링**:
   변경된 것이 없을 때도 렌더링 발생 → dirty 플래그로 최적화

   ```javascript
   let isDirty = true;
   
   function render() {
     if (isDirty) {
       // 실제 렌더링 수행...
       isDirty = false;
     }
     
     requestAnimationFrame(render);
   }
   
   function updateSomething() {
     // 변경 시 dirty 플래그 설정
     isDirty = true;
   }
   ```

3. **GPU 활용 부족**:
   CPU에서 모든 계산 수행 → WebGL 또는 WebGPU로 전환 실험

## 🔄 OffscreenCanvas 활용

더 나아가 OffscreenCanvas를 사용해 렌더링까지 워커로 위임하는 방법도 실험했다:

```javascript
// main.js
const canvas = document.getElementById('game-canvas');
const offscreen = canvas.transferControlToOffscreen();
const worker = new Worker('render-worker.js');

// 오프스크린 캔버스를 워커로 전송 (소유권 이전)
worker.postMessage({ 
  type: 'INIT', 
  canvas: offscreen 
}, [offscreen]);

// render-worker.js
let canvas;
let ctx;
let particles = [];

onmessage = function(event) {
  const { type, canvas: receivedCanvas } = event.data;
  
  if (type === 'INIT') {
    canvas = receivedCanvas;
    ctx = canvas.getContext('2d');
    initParticles();
    requestAnimationFrame(renderLoop);
  }
};

function renderLoop() {
  // 렌더링 및 업데이트 로직...
  
  requestAnimationFrame(renderLoop);
}
```

## 🔄 워커 풀 구현 실험

여러 워커를 효율적으로 관리하는 워커 풀 패턴도 구현해 보았다:

```javascript
class WorkerPool {
  constructor(size) {
    this.size = size;
    this.workers = [];
    this.queue = [];
    this.activeWorkers = 0;
    
    // 워커 풀 초기화
    for (let i = 0; i < size; i++) {
      const worker = new Worker('worker.js');
      
      worker.onmessage = (event) => {
        // 작업 완료 처리
        const { taskId, result } = event.data;
        const task = this.queue.find(t => t.id === taskId);
        
        if (task && task.resolve) {
          task.resolve(result);
        }
        
        // 워커를 다시 사용 가능 상태로 표시
        this.activeWorkers--;
        
        // 대기 중인 작업이 있으면 실행
        this.processQueue();
      };
      
      this.workers.push({
        worker,
        busy: false
      });
    }
  }
  
  // 작업 추가
  enqueue(taskType, data) {
    return new Promise((resolve, reject) => {
      const taskId = Math.random().toString(36).substr(2, 9);
      
      this.queue.push({
        id: taskId,
        type: taskType,
        data,
        resolve,
        reject
      });
      
      this.processQueue();
    });
  }
  
  // 대기 중인 작업 처리
  processQueue() {
    if (this.queue.length === 0) return;
    if (this.activeWorkers >= this.size) return;
    
    // 사용 가능한 워커 찾기
    const workerInfo = this.workers.find(w => !w.busy);
    if (!workerInfo) return;
    
    // 워커 사용 중으로 표시
    workerInfo.busy = true;
    this.activeWorkers++;
    
    // 대기열에서 작업 가져오기
    const task = this.queue.shift();
    
    // 워커에 작업 전송
    workerInfo.worker.postMessage({
      taskId: task.id,
      type: task.type,
      data: task.data
    });
  }
  
  // 모든 워커 종료
  terminate() {
    this.workers.forEach(workerInfo => {
      workerInfo.worker.terminate();
    });
    
    this.workers = [];
    this.queue = [];
    this.activeWorkers = 0;
  }
}

// 워커 풀 사용 예시
const pool = new WorkerPool(navigator.hardwareConcurrency || 4);

// 여러 작업 동시 처리
async function processImages(images) {
  const results = await Promise.all(
    images.map(image => 
      pool.enqueue('PROCESS_IMAGE', { imageData: image })
    )
  );
  
  return results;
}
```

## 📊 성능 측정 및 비교

여러 접근 방식의 성능을 Chrome DevTools의 Performance 탭으로 분석했다:

| 구현 방식 | FPS | CPU 사용률 | 메모리 사용량 | 느낌 |
|---------|-----|-----------|------------|-----|
| 단일 스레드 | ~30 | 90-100% | 낮음 | 버벅임 |
| 웹 워커 + 메시지 | ~55 | 70-80% | 중간 | 좋음 |
| 웹 워커 + SharedArrayBuffer | ~58 | 65-75% | 중간 | 매우 좋음 |
| OffscreenCanvas | ~60 | 60-70% | 높음 | 부드러움 |

확실히 워커를 활용하면 메인 스레드 부하가 줄어들어 UI 반응성이 크게 향상되는 것을 확인했다.

## 🌟 Service Worker와 PWA 연계

웹 워커와 함께 Service Worker를 활용한 PWA(Progressive Web App) 최적화도 시도해 보았다:

```javascript
// service-worker.js
self.addEventListener('install', event => {
  event.waitUntil(
    caches.open('app-v1').then(cache => {
      return cache.addAll([
        '/',
        '/index.html',
        '/styles.css',
        '/app.js',
        '/worker.js',
        '/images/icon.png'
      ]);
    })
  );
});

self.addEventListener('fetch', event => {
  event.respondWith(
    caches.match(event.request).then(response => {
      if (response) {
        return response; // 캐시에서 찾음
      }
      
      // 네트워크 요청 및 캐시에 추가
      return fetch(event.request).then(response => {
        // 유효한 응답인지 확인
        if (!response || response.status !== 200 || response.type !== 'basic') {
          return response;
        }
        
        // 응답 복제 (스트림은 한 번만 사용 가능)
        const responseToCache = response.clone();
        
        caches.open('app-v1').then(cache => {
          cache.put(event.request, responseToCache);
        });
        
        return response;
      });
    })
  );
});
```

## 🤔 어려웠던 부분 & 앞으로의 학습 방향

1. **디버깅 복잡성**: 웹 워커 내부 동작 디버깅이 어려움
2. **브라우저 호환성**: SharedArrayBuffer, OffscreenCanvas 등은 아직 지원이 제한적
3. **아키텍처 설계**: 어떤 작업을 워커로 분리할지 결정하는 것이 생각보다 복잡함

## 🪬 오늘의 교훈

JavaScript의 단일 스레드 모델은 여전히 큰 제약이지만, 웹 워커와 최신 API를 활용하면 꽤 강력한 멀티스레딩 애플리케이션을 구현할 수 있다는 점을 실감했다. 특히 프레임워크에 의존하지 않고 순수 JavaScript로 성능 최적화를 고민해보는 과정이 매우 유익했다.

무조건 워커를 사용하는 것보다는 작업의 특성을 고려해 적절한 기법을 선택하는 것이 중요하다. 단순히 UI를 블로킹하지 않는 것을 넘어, 작업을 어떻게 분할하고 스레드 간 통신 오버헤드를 최소화할지 고민하는 것이 핵심이다.

내일부터는 이 모든 기법을 종합해 실제 프로젝트에 적용하고, 더 깊이 있는 최적화를 실험해볼 예정이다.

---

## 회고 요약

- 웹 워커를 활용한 멀티스레딩 구현
- SharedArrayBuffer와 Atomics API 학습
- 캔버스 애니메이션 최적화 프로젝트 진행
- OffscreenCanvas로 렌더링 성능 개선
- 워커 풀 패턴 구현 및 실험
- Service Worker와 PWA 연계 최적화
- 여러 방식의 성능 측정 및 비교 분석

# 이벤트 루프 심화 이해와 비동기 최적화 기법 

오늘은 JavaScript의 이벤트 루프에 대해 더 깊이 파고들었다. 특히 비동기 작업의 실행 순서와 최적화 기법에 중점을 두고 공부했다.

## 🔄 이벤트 루프 심화 이해하기

지난번에 배운 비동기 프로그래밍 개념을 바탕으로 JavaScript 엔진이 어떻게 동작하는지 더 깊이 파악했다:

```javascript
console.log('시작');

setTimeout(() => {
  console.log('타임아웃 콜백');
}, 0);

Promise.resolve().then(() => {
  console.log('프로미스 콜백');
});

console.log('종료');

// 출력 순서:
// 시작
// 종료
// 프로미스 콜백
// 타임아웃 콜백
```

### 이벤트 루프 구성 요소 분석

1. **콜 스택(Call Stack)**: 함수 호출을 추적하는 데이터 구조
2. **태스크 큐(Task Queue)**: setTimeout, setInterval 등의 콜백이 대기하는 큐
3. **마이크로태스크 큐(Microtask Queue)**: Promise 콜백이 대기하는 큐 (태스크 큐보다 우선순위 높음)
4. **렌더링 단계**: 브라우저 UI 업데이트 (레이아웃, 페인트 등)

### 실전 활용 예시

```javascript
// 🔴 안 좋은 예: 무거운 계산으로 UI 차단
function calculatePrimes(num) {
  const primes = [];
  for (let i = 2; i <= num; i++) {
    let isPrime = true;
    for (let j = 2; j < i; j++) {
      if (i % j === 0) {
        isPrime = false;
        break;
      }
    }
    if (isPrime) primes.push(i);
  }
  return primes;
}

document.getElementById('calculate-btn').addEventListener('click', () => {
  const result = calculatePrimes(100000); // 메인 스레드 차단
  displayResults(result);
});

// 🟢 좋은 예: 무거운 작업 청크로 분할
function calculatePrimesInChunks(num, onProgress, onComplete) {
  let i = 2;
  const primes = [];
  
  function processChunk() {
    const startTime = performance.now();
    
    while (i <= num && performance.now() - startTime < 10) {
      let isPrime = true;
      for (let j = 2; j < i; j++) {
        if (i % j === 0) {
          isPrime = false;
          break;
        }
      }
      if (isPrime) primes.push(i);
      i++;
    }
    
    // 진행률 보고
    onProgress(Math.min(100, Math.floor((i / num) * 100)));
    
    if (i <= num) {
      // 다음 프레임에서 계속 처리
      requestAnimationFrame(processChunk);
    } else {
      // 완료
      onComplete(primes);
    }
  }
  
  // 첫 청크 시작
  requestAnimationFrame(processChunk);
}

document.getElementById('calculate-btn').addEventListener('click', () => {
  const progressBar = document.getElementById('progress-bar');
  
  calculatePrimesInChunks(
    100000,
    (progress) => {
      progressBar.style.width = `${progress}%`;
    },
    (result) => {
      displayResults(result);
    }
  );
});
```

## 📊 브라우저 렌더링 성능 디버깅

Chrome DevTools의 Performance와 Rendering 탭을 활용해 렌더링 성능을 분석하는 방법을 배웠다:

### 주요 성능 지표

1. **First Paint (FP)**: 첫 픽셀이 화면에 그려지는 시점
2. **First Contentful Paint (FCP)**: 텍스트나 이미지가 처음 표시되는 시점
3. **Largest Contentful Paint (LCP)**: 가장 큰 컨텐츠가 표시되는 시점
4. **Time to Interactive (TTI)**: 사용자와 상호작용이 가능해지는 시점

### 렌더링 병목 현상 분석 방법

```javascript
