## 🤔 인터렉티브 웹앱 최적화 프로젝트

실제 프로젝트에 학습한 내용을 적용해 봤다:

```javascript
class OptimizedApp {
  constructor() {
    this.tasks = [];
    this.isProcessingTasks = false;
    this.initEventListeners();
  }
  
  initEventListeners() {
    // 사용자 입력 이벤트 처리
    document.getElementById('user-input').addEventListener('input', 
      this.debounce(this.handleUserInput.bind(this), 200)
    );
    
    // 스크롤 이벤트 처리
    window.addEventListener('scroll', 
      this.throttle(this.handleScroll.bind(this), 100)
    );
    
    // 애니메이션 시작 버튼
    document.getElementById('animate-btn').addEventListener('click', () => {
      this.startAnimation();
    });
  }
  
  handleUserInput(event) {
    const value = event.target.value;
    
    // 무거운 작업을 태스크 큐로 이동
    this.scheduleTask(() => {
      this.processUserInput(value);
    });
  }
  
  processUserInput(value) {
    // 복잡한 처리 로직...
    console.log('입력 처리 완료:', value);
  }
  
  handleScroll() {
    // 가시성 확인 및 필요한 요소만 업데이트
    const elements = document.querySelectorAll('.lazy-load');
    
    elements.forEach(element => {
      if (this.isElementInViewport(element) && !element.dataset.loaded) {
        element.dataset.loaded = true;
        this.loadContent(element);
      }
    });
  }
  
  isElementInViewport(el) {
    const rect = el.getBoundingClientRect();
    return (
      rect.top >= 0 &&
      rect.left >= 0 &&
      rect.bottom <= window.innerHeight &&
      rect.right <= window.innerWidth
    );
  }
  
  loadContent(element) {
    // 이미지나 컨텐츠 로드 로직...
  }
  
  startAnimation() {
    let frame = 0;
    const animate = (timestamp) => {
      // 애니메이션 로직...
      frame++;
      
      // 다음 프레임 요청
      this.animationId = requestAnimationFrame(animate);
    };
    
    this.animationId = requestAnimationFrame(animate);
  }
  
  scheduleTask(task) {
    this.tasks.push(task);
    
    if (!this.isProcessingTasks) {
      this.processTasks();
    }
  }
  
  processTasks() {
    this.isProcessingTasks = true;
    
    requestIdleCallback(deadline => {
      while (deadline.timeRemaining() > 0 && this.tasks.length > 0) {
        const task = this.tasks.shift();
        task();
      }
      
      if (this.tasks.length > 0) {
        // 아직 남은 작업이 있으면 다시 스케줄링
        this.processTasks();
      } else {
        this.isProcessingTasks = false;
      }
    });
  }
  
  // 유틸리티 메서드
  debounce(func, wait) {
    let timeout;
    return function(...args) {
      clearTimeout(timeout);
      timeout = setTimeout(() => func(...args), wait);
    };
  }
  
  throttle(func, limit) {
    let inThrottle;
    return function(...args) {
      if (!inThrottle) {
        func(...args);
        inThrottle = true;
        setTimeout(() => inThrottle = false, limit);
      }
    };
  }
}

// 앱 초기화
const app = new OptimizedApp();
```

