2. **배열 메서드 이해하기**:
   ```javascript
   const numbers = [1, 2, 3, 4, 5];
   
   // forEach로 각 요소 순회
   numbers.forEach(function(number) {
     console.log(number * 2);
   });
   
   // map으로 새 배열 만들기
   const doubled = numbers.map(function(number) {
     return number * 2;
   });
   
   // filter로 조건에 맞는 요소만 선택
   const evenNumbers = numbers.filter(function(number) {
     return number % 2 === 0;
   });
