## 🚀 미니 프로젝트: 할일 목록 만들기

이번 주에 배운 내용을 활용해 간단한 할일 목록 앱을 만들어보았다. 아직 기능은 단순하지만 HTML, CSS, JavaScript를 모두 활용할 수 있었다:

```html
<!DOCTYPE html>
<html lang="ko">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>할일 목록</title>
  <style>
    :root {
      --primary-color: #3498db;
      --light-gray: #f4f4f4;
    }
    
    body {
      font-family: 'Arial', sans-serif;
      line-height: 1.6;
      margin: 0;
      padding: 20px;
    }
    
    .container {
      max-width: 500px;
      margin: 0 auto;
      background: white;
      padding: 20px;
      border-radius: 5px;
      box-shadow: 0 0 10px rgba(0,0,0,0.1);
    }
    
    h1 {
      text-align: center;
      color: var(--primary-color);
    }
    
    .task-form {
      display: flex;
      margin-bottom: 20px;
    }
    
    #task-input {
      flex: 1;
      padding: 10px;
      border: 1px solid #ddd;
      border-radius: 4px 0 0 4px;
    }
    
    .add-button {
      background: var(--primary-color);
      color: white;
      border: none;
      padding: 10px 15px;
      border-radius: 0 4px 4px 0;
      cursor: pointer;
    }
    
    .task-list {
      list-style: none;
      padding: 0;
    }
    
    .task-item {
      display: flex;
      justify-content: space-between;
      align-items: center;
      padding: 10px;
      margin-bottom: 10px;
      background: var(--light-gray);
      border-radius: 4px;
    }
    
    .delete-button {
      background: #e74c3c;
      color: white;
      border: none;
      padding: 5px 10px;
      border-radius: 3px;
      cursor: pointer;
    }
  </style>
</head>
<body>
  <div class="container">
    <h1>할일 목록</h1>
    
    <form class="task-form">
      <input type="text" id="task-input" placeholder="할일을 입력하세요">
      <button type="submit" class="add-button">추가</button>
    </form>
    
    <ul class="task-list" id="task-list">
      <!-- 할일 항목이 여기에 추가됨 -->
    </ul>
  </div>

  <script>
    // DOM 요소 가져오기
    const taskForm = document.querySelector('.task-form');
    const taskInput = document.querySelector('#task-input');
    const taskList = document.querySelector('#task-list');
    
    // 저장된 할일 불러오기
    function loadTasks() {
      const tasks = getTasks();
      
      tasks.forEach(function(task) {
        addTaskToDOM(task);
      });
    }
    
    // 로컬 스토리지에서 할일 불러오기
    function getTasks() {
      const tasksJSON = localStorage.getItem('tasks');
      if (tasksJSON === null) {
        return [];
      }
      return JSON.parse(tasksJSON);
    }
    
    // 로컬 스토리지에 할일 저장하기
    function saveTasks(tasks) {
      localStorage.setItem('tasks', JSON.stringify(tasks));
    }
    
    // DOM에 할일 추가하기
    function addTaskToDOM(task) {
      const li = document.createElement('li');
      li.className = 'task-item';
      
      const taskText = document.createElement('span');
      taskText.textContent = task;
      
      const deleteButton = document.createElement('button');
      deleteButton.className = 'delete-button';
      deleteButton.textContent = '삭제';
      
      // 삭제 버튼 이벤트 리스너
      deleteButton.addEventListener('click', function() {
        li.remove();
        removeTask(task);
      });
      
      li.appendChild(taskText);
      li.appendChild(deleteButton);
      taskList.appendChild(li);
    }
    
    // 할일 삭제하기
    function removeTask(taskToRemove) {
      let tasks = getTasks();
      tasks = tasks.filter(function(task) {
        return task !== taskToRemove;
      });
      saveTasks(tasks);
    }
    
    // 폼 제출 이벤트 처리
    taskForm.addEventListener('submit', function(event) {
      event.preventDefault();
      
      const taskText = taskInput.value.trim();
      
      if (taskText === '') {
        alert('할일을 입력해주세요!');
        return;
      }
      
      // 할일 추가
      addTaskToDOM(taskText);
      
      // 로컬 스토리지에 저장
      const tasks = getTasks();
      tasks.push(taskText);
      saveTasks(tasks);
      
      // 입력 필드 초기화
      taskInput.value = '';
    });
    
    // 페이지 로드 시 할일 불러오기
    loadTasks();
  </script>
</body>
</html>
```

## 🤔 현재 어려움을 겪는 부분

1. **JavaScript 비동기 처리**: `setTimeout`이나 `fetch` 같은 비동기 함수들의 개념이 아직 완전히 와닿지 않는다. 콜백 함수가 언제 실행되는지 가끔 헷갈린다.

2. **CSS 레이아웃**: Flexbox를 배웠지만 복잡한 레이아웃을 구성할 때 여전히 요소들이 의도한 대로 배치되지 않는 경우가 많다. 특히 반응형으로 만들 때 어려움을 느낀다.

3. **JavaScript 스코프**: 변수의 스코프와 호이스팅 개념이 아직 확실하게 이해되지 않아 가끔 예상치 못한 결과가 나온다.

